// AUTO-GENERATED from src/assets/logo-ticket.png. Do not edit by hand.
// ESC/POS GS v 0 raster blocks (header + monochrome data), base64-encoded.
export const LOGO_RASTER_58_B64 = "";
export const LOGO_RASTER_80_B64 = "";

export function getLogoRaster(widthMm: number): Uint8Array {
  const b64 = widthMm === 58 ? LOGO_RASTER_58_B64 : LOGO_RASTER_80_B64;
  const bin = atob(b64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}
